// Remove tags HTML e extrai texto limpo
const html = $input.first().json.data || $input.first().json || '';
const webhookData = $('Webhook URL').first().json;
const sourceUrl = webhookData.body?.url || webhookData.url || '';

// Remove scripts, styles e tags
let text = String(html)
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\s{2,}/g, ' ')
  .trim();

// Limita a 4000 chars para o prompt da IA
if (text.length > 4000) text = text.slice(0, 4000) + '...';

return [{ json: { text, source_url: sourceUrl } }];

