// Parseia resposta do Claude e formata para o frontend
const response = $input.first().json;
const pageData = $('Extrair Texto').first().json;

let words = [];
try {
  const text = response.content?.[0]?.text || '[]';
  const match = text.match(/\[[\s\S]*\]/);
  if (match) words = JSON.parse(match[0]);
} catch { words = []; }

// Adiciona source_url em cada item
words = words.map(w => ({
  ...w,
  source_type: 'website',
  source_title: pageData.source_url
}));

return [{ json: { words, count: words.length, source_url: pageData.source_url } }];
